SELECT AVG(range) 
FROM robot_sensors 
WHERE placement = 'front' AND sensor_status = 'online';

SELECT algorithm_type
FROM algorithm_versions
WHERE algorithm_name = 'MPC_Control';

SELECT rs.sensor_id, rs.sensor_type, rs.description, rs.placement
FROM robot_sensors rs
WHERE rs.sensor_status = 'Maintenance Required' AND DATE(rs.calibration_date) < DATE('now', '-2 year');

SELECT sensor_type, MAX(accuracy) AS Highest_Accuracy
FROM robot_sensors
GROUP BY sensor_type;

SELECT sensor_type, placement, AVG(accuracy) AS Average_Accuracy
FROM robot_sensors
GROUP BY sensor_type, placement;

SELECT AVG(accuracy) AS average_accuracy 
FROM robot_sensors 
WHERE sensor_type = 'IMU';
